"use strict";function formatNumber(t,a,e){const n=Number(t);switch(a){case"integer":return Math.round(n).toString();case"float-1":return n.toFixed(1);case"float-2":return n.toFixed(2);default:return e===1||e%1===0?Math.round(n).toString():e<.1?n.toFixed(2):n.toFixed(1)}}document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".numeric-slider-range").forEach(t=>{const a=t.id,e=document.getElementById(`${a}_min`),n=document.getElementById(`${a}_max`),r=document.getElementById(`${a}_text`),u=t.dataset.unit||"",c=Number(t.dataset.range_min),s=Number(t.dataset.range_max),o=Number(t.dataset.step)||1,x=Number(t.dataset.cur_min)||c,f=Number(t.dataset.cur_max)||s,d=t.dataset.number_format||"auto";noUiSlider.create(t,{start:[x,f],connect:!0,range:{min:c,max:s},step:o}),t.noUiSlider.on("update",g=>{const[i,m]=g;e&&(e.value=i),n&&(n.value=m);const b=formatNumber(i,d,o),M=formatNumber(m,d,o);r&&(r.textContent=`${b}${u} - ${M}${u}`)})})});
